const wfItem = $('listarWorkflows').first();
const exItem = $('ListarExecucoes').first();

const workflows = (wfItem.json?.data || []).map(w => ({
  id: w.id,
  name: w.name,
  active: w.active,
  createdAt: w.createdAt,
  updatedAt: w.updatedAt,
  tags: (w.tags || []).map(t => t.name || t),
}));

const executions = (exItem.json?.data || []).map(e => ({
  id: e.id,
  workflowId: e.workflowId || e.workflowData?.id,
  workflowName: e.workflowData?.name || '',
  status: e.status,
  startedAt: e.startedAt,
  stoppedAt: e.stoppedAt,
  finished: e.finished,
}));

// Compute per-workflow stats
const wfMap = {};
workflows.forEach(w => {
  wfMap[w.id] = { ...w, totalExec: 0, failedExec: 0, successExec: 0, runningExec: 0, waitingExec: 0, totalRuntimeMs: 0, execCount: 0 };
});

executions.forEach(e => {
  const wId = String(e.workflowId);
  if (!wfMap[wId]) {
    wfMap[wId] = { id: wId, name: e.workflowName || `Workflow ${wId}`, active: false, tags: [], totalExec: 0, failedExec: 0, successExec: 0, runningExec: 0, waitingExec: 0, totalRuntimeMs: 0, execCount: 0 };
  }
  const wf = wfMap[wId];
  wf.totalExec++;
  if (e.status === 'error' || e.status === 'failed' || e.status === 'crashed') wf.failedExec++;
  else if (e.status === 'success') wf.successExec++;
  else if (e.status === 'running') wf.runningExec++;
  else if (e.status === 'waiting') wf.waitingExec++;
  if (e.startedAt && e.stoppedAt) {
    const ms = new Date(e.stoppedAt).getTime() - new Date(e.startedAt).getTime();
    if (ms > 0) { wf.totalRuntimeMs += ms; wf.execCount++; }
  }
});

const workflowStats = Object.values(wfMap).map(w => ({
  id: w.id,
  name: w.name,
  active: w.active,
  tags: w.tags,
  totalExec: w.totalExec,
  successExec: w.successExec,
  failedExec: w.failedExec,
  runningExec: w.runningExec,
  waitingExec: w.waitingExec,
  failureRate: w.totalExec > 0 ? Math.round((w.failedExec / w.totalExec) * 10000) / 100 : 0,
  avgRuntimeMs: w.execCount > 0 ? Math.round(w.totalRuntimeMs / w.execCount) : 0,
  avgRuntimeSec: w.execCount > 0 ? Math.round((w.totalRuntimeMs / w.execCount) / 10) / 100 : 0,
})).sort((a, b) => b.totalExec - a.totalExec);

const totalExec = executions.length;
const successExec = executions.filter(e => e.status === 'success').length;
const failedExec = executions.filter(e => e.status === 'error' || e.status === 'failed' || e.status === 'crashed').length;
const runningExec = executions.filter(e => e.status === 'running').length;

let totalRt = 0, rtCount = 0;
executions.forEach(e => {
  if (e.startedAt && e.stoppedAt) {
    const ms = new Date(e.stoppedAt).getTime() - new Date(e.startedAt).getTime();
    if (ms > 0) { totalRt += ms; rtCount++; }
  }
});
const avgRuntimeSec = rtCount > 0 ? Math.round((totalRt / rtCount) / 10) / 100 : 0;

return [{ json: {
  summary: { totalExec, successExec, failedExec, runningExec, avgRuntimeSec, totalWorkflows: workflows.length },
  workflows: workflowStats,
  executions: executions,
} }];
